create table badges (id uuid default uuid_generate_v4() primary key, name text not null, icon text not null, description text not null, total integer not null, category text not null, emoji text, image_url text, created_at timestamp with time zone default timezone('utc'::text, now()) not null); create table user_badges (id uuid default uuid_generate_v4() primary key, user_id uuid references auth.users(id) on delete cascade not null, badge_id uuid references badges(id) on delete cascade not null, progress integer default 0 not null, is_unlocked boolean default false not null, unlocked_at timestamp with time zone, created_at timestamp with time zone default timezone('utc'::text, now()) not null, unique(user_id, badge_id)); create index user_badges_user_id_idx on user_badges(user_id); create index user_badges_badge_id_idx on user_badges(badge_id);
